                    param_name = rp[1:-1]
                    params[param_name] = pp
                    # Don't increment score for parameterized segments
                elif rp == pp:
                    # Static segment match - increment score
                    score += 1
                else:
                    # No match
                    match = False
                    break

            if match and score > best_score:
                best_match = handler
                best_params = params
                best_score = score

        if best_match is not None:
            return (best_match, best_params)
        return None

